INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-03530', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多成人可能因回顧過往人際關係的遺憾之處，會開始產生思考寬恕的議題。有關寬恕的敘述， 下列何者正確？', '["寬恕與和解相同，都需要透過雙方共同努力，才能實踐此結果", "寬恕他人並不等同原諒，只是讓當事人知道如何避免再次受傷", "寬恕是一種理性的過程，能澈底顛覆對自己、對他人、對傷害、對脆弱的想法", "寬恕雖有解放情緒的效果，但不等同放下對某人的敵意或攻擊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03531', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於生產後情況的敘述，下列何者錯誤？', '["寶寶出生後，產婦必然罹患產後憂鬱症", "若發現子女有發展缺陷時，有些家長在初期可能會否認子女有問題", "親餵母奶但卻面臨新生兒吸吮不順時，可能增加新手家長的壓力", "使用背帶有助於提供親子緊密互動的機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03532', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於重組家庭的親子關係正向發展，下列做法何者最沒有助益？', '["家庭的次系統運作，應以滿足子女的需求為優先，配偶或伴侶關係次之", "繼親家長應先當孩子的「朋友」，避免太快當個規訓者", "重組家庭的家長應與沒有監護權的家長維持積極正向關係", "繼親家長在和孩子建立關係時，須考量性別和個別差異，來探索適當的互動之道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03533', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '親子間的互動會決定親子關係的品質，若家長認為透過規則的設立和執行就能幫助子女成長，要 子女尊重家長、聽話、認分地遵守規則，較沒討論餘地，是屬於Baumrind（1971）提出親職教養 的那一個原型？', '["縱容型（permissive）", "獨裁型（authoritarian）", "權威型（authoritative）", "漠不關心型（uninvolved）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03534', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者最能夠描述去習慣化（dishabituation）的意涵？', '["觀察嬰幼兒的注意力，瞭解他們專注在同一事物或刺激的時間和過程", "觀察嬰幼兒的注意力，瞭解他們將注意力轉移到新事物的時間和過程", "觀察嬰幼兒習慣的建立，測量他們建立新習慣所需要的時間和過程", "觀察嬰幼兒習慣的建立，測量他們摒棄舊習慣所需要的時間和過程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03535', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會對性侵害議題存有不少刻板印象。對強暴與性侵害的敘述，下列何者正確？', '["性侵害受害者不一定具有特定性別、性傾向、年齡、長相、穿著等特徵", "性侵害受害者將處在強烈憤怒、憂鬱中，因此不會有罪惡感或自責等感受", "強暴與性侵害加害人多半是陌生人", "同性戀者不會有發生強暴與性侵害的風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03536', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項國家或企業政策，無助於降低有育兒需求者在就業與職場上的壓力？', '["對其伴侶提供陪產假、家庭照顧假、育嬰假", "提供強制親職與育兒教育訓練，以提升育兒效率", "提供托老、托幼等照顧資源", "由企業透過諮商及教育方案，協助員工協調工作與家庭雙重角色產生之壓力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03537', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '隨著老人特質的多元化和差異性與日俱增，提供新住民高齡者服務時，社會工作者應具備的知能， 下列何者錯誤？', '["應對新住民高齡者原生文化、語言與其生命歷史，保持高度敏感度", "與來自該文化或懂該族母語的社會工作者合作，以降低自身刻板印象", "提供新住民高齡長者國語教育，以利雙方溝通與提供服務", "以該新住民高齡長者之家庭整體，作為評估照顧服務需求之範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03538', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '美國研究機構調查指出，自2009至2012年認為美國經歷貧窮與富裕嚴重衝突的人們從47%增至 66%，加上大多數美國人感受經濟與機會日益減少，促使人民走上街頭的社會行動，這屬於下列 何種理論的觀點？', '["功能論", "實踐理論", "衝突理論", "符號互動論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03539', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '國外研究顯示，「來自低社經地位群體的兒童在學校的出席率以及功課好的比率較低、輟學率則高 於來自高社經地位群體的兒童，這樣的影響可能持續到成年期。」從生態理論觀點，家庭的社經 地位是那一個層次的系統？', '["鉅視系統", "微視系統", "外在系統", "中介系統"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
